# pip install prefect anthropic
from prefect import flow, task
from prefect.tasks import task_input_hash
from datetime import timedelta

@task(cache_key_fn=task_input_hash, cache_expiration=timedelta(hours=1), retries=2)
def fetch_articles(topic: str) -> list[dict]:
    # Simulated: real implementation fetches from a news API
    return [
        {"title": "AI agents reshape enterprise workflows", "content": "..."},
        {"title": "New LLM benchmarks released", "content": "..."},
    ]

@task(retries=3, retry_delay_seconds=10)
def summarise_article(article: dict) -> str:
    from anthropic import Anthropic
    client = Anthropic()
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=150,
        messages=[{
            "role": "user",
            "content": f"Summarise in 2 sentences: {article['title']}\n{article['content']}"
        }]
    )
    return resp.content[0].text

@task
def compile_digest(summaries: list[str], topic: str) -> str:
    return f"# {topic} Digest\n\n" + "\n\n".join(
        f"{i+1}. {s}" for i, s in enumerate(summaries)
    )

@task
def send_email(digest: str, recipient: str) -> None:
    print(f"Sending digest to {recipient}:\n{digest}")

@flow(name="weekly-ai-digest", log_prints=True)
def weekly_digest_flow(topic: str = "AI", recipient: str = "team@example.com") -> None:
    articles = fetch_articles(topic)
    # .map() runs each article in a separate task concurrently
    summaries = summarise_article.map(articles)
    digest = compile_digest(summaries, topic)
    send_email(digest, recipient)

if __name__ == "__main__":
    weekly_digest_flow()

